const ALIAS = {};
for (const full of Object.keys(ICONS)) for (const t of full.split(",").map((x) => x.trim())) if (!(t in ALIAS)) ALIAS[t] = full;

function get(name) { return ICONS[name] || ICONS[ALIAS[name]] || null; }

// 官方容器同构: <svg viewBox fill=none><path stroke=none fill-rule fill=currentColor/></svg>
function svg(name, size, style) {
  const ic = get(name);
  if (!ic) return "";
  const paths = ic.paths.map((d) => '<path d="' + d + '" stroke="none" fill-rule="' + (ic.fillRule || "evenodd") + '" fill="currentColor"/>').join("");
  return '<svg width="' + (size || 14) + '" height="' + (size || 14) + '" viewBox="' + ic.viewBox + '" fill="none" xmlns="http://www.w3.org/2000/svg"' + (style ? ' style="' + style + '"' : "") + ">" + paths + "</svg>";
}

function names() { return Object.keys(ICONS); }

module.exports = { svg, get, names, ICONS, ALIAS };
